cat > /tmp/test_char_sign.c << 'EOF'
#include <stdio.h>

int main() {
  char signed_arr[256];
  unsigned char unsigned_arr[256];

  // Initialize both
  for (int i = 0; i < 256; i++) {
    signed_arr[i] = i;
    unsigned_arr[i] = i;
  }

  int idx = 224; // 0xE0
  printf("Accessing [224]:\n");
  printf("  signed_arr[224] as char: %d\n", (int)signed_arr[224]);
  printf("  unsigned_arr[224] as unsigned char: %u\n", (unsigned int)unsigned_arr[224]);

  // Show the problem with using negative values in bit operations
  char val_signed = signed_arr[224];
  unsigned char val_unsigned = unsigned_arr[224];

  printf("\nWhen used for bit operations:\n");
  printf("  signed_arr[224] / 8 = %d (WRONG for bitmap index)\n", val_signed / 8);
  printf("  unsigned_arr[224] / 8 = %u (CORRECT for bitmap index)\n", val_unsigned / 8);

  return 0;
}
EOF
gcc /tmp/test_char_sign.c -o /tmp/test_char_sign && /tmp/test_char_sign
